INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(7, 1, '08', '현금흐름표 구조', '문서에서 현금흐름표(CFO)가 나타내는 것은?', '설비·지분 투자에서 발생한 현금', '본업에서 창출한 현금', '차입·배당·자사주로 인한 현금 변동', '자유롭게 쓸 수 있는 잉여 현금', 2, '문서에서 영업현금흐름(CFO)은 본업에서 창출한 현금이며, 건강한 회사는 꾸준히 플러스(+)를 유지한다고 설명합니다.'),
(7, 2, '08', '현금흐름표 구조', '문서에서 투자현금흐름(CFI)이 성장기에 마이너스(-)인 이유는?', '배당을 많이 지급하기 때문', '자사주를 매입하기 때문', '설비·지분 투자를 늘리기 때문', '차입금을 상환하기 때문', 3, '문서 현금흐름표 구조 표에서 투자현금흐름(CFI)은 설비·지분 투자에 해당하며, 성장기에는 마이너스(-)가 정상이라고 설명합니다.'),
(7, 3, '08', 'FCF 공식', '문서에서 FCF(잉여현금흐름)의 계산 공식으로 제시된 것은?', 'FCF = 영업이익 - 법인세', 'FCF = 당기순이익 + 감가상각비', 'FCF = CFO - Capex', 'FCF = 매출액 - 영업비용', 3, '문서 현금흐름표 flowchart에서 FCF = CFO - Capex로 정의되며, 자유롭게 쓸 수 있는 현금을 나타냅니다.'),
(7, 4, '08', '현금흐름 패턴', '문서에서 CFO +, CFI -, CFF -인 기업 유형은?', '초기 성장 기업 (아직 적자, 외부 자금 의존)', '구조조정 중 (자산 매각으로 부채 상환)', '성장 기업 (벌지만 차입도 해서 투자)', '이상적인 성숙 기업 (벌어서 투자하고 배당)', 4, '문서 현금흐름 패턴 표에서 CFO +, CFI -, CFF -는 이상적인 성숙 기업으로, 벌어서 투자하고 배당하는 구조입니다.'),
(7, 5, '08', '현금흐름 패턴', '문서에서 CFO -, CFI -, CFF +인 기업 유형은?', '이상적인 성숙 기업', '성장 기업 (벌지만 차입도 해서 투자)', '초기 성장 기업 (아직 적자, 외부 자금 의존)', '구조조정 중 (자산 매각으로 부채 상환)', 3, '문서 현금흐름 패턴 표에서 CFO -, CFI -, CFF +는 초기 성장 기업으로, 아직 적자이며 외부 자금에 의존한다고 설명합니다.'),
(7, 6, '08', '순이익 vs CFO', '문서에서 매출채권 증가가 영업현금흐름(CFO)에 미치는 영향은?', '영업현금흐름 증가(+)', '영업현금흐름 감소(-)', '영향 없음', '법인세 절감 효과로 증가(+)', 2, '문서 순이익과 영업현금흐름이 다르게 움직이는 이유 표에서 매출채권 증가는 CFO 감소(-) 효과를 가져오며, 팔았지만 아직 현금을 못 받은 상태를 의미합니다.'),
(7, 7, '08', '순이익 vs CFO', '문서에서 감가상각비가 영업현금흐름(CFO)에 미치는 영향과 이유는?', 'CFO 감소(-), 실제 현금 유출이 있기 때문', 'CFO 증가(+), 비용 처리됐지만 현금 유출은 없는 항목이기 때문', 'CFO 감소(-), 고정비 부담이 증가하기 때문', 'CFO에 영향 없음, 비현금 항목이기 때문', 2, '문서에서 감가상각비는 비용으로 처리됐지만 실제 현금 유출이 없으므로 CFO를 증가(+)시키는 항목으로 설명됩니다.'),
(7, 8, '08', '순이익 vs CFO', '문서에서 재고자산 증가가 CFO에 미치는 영향은?', 'CFO 증가(+), 판매를 준비하는 단계이기 때문', 'CFO 감소(-), 현금이 재고에 묶인 상태이기 때문', '영향 없음, 재고는 자산 항목이기 때문', 'CFO 증가(+), 비용 지급을 미룬 상태이기 때문', 2, '문서에서 재고자산 증가는 CFO 감소(-) 효과를 가져오며, 현금이 재고에 묶인 상태를 의미한다고 설명합니다.'),
(7, 9, '08', '순이익 vs CFO', '문서에서 매입채무 증가가 CFO에 미치는 영향은?', 'CFO 감소(-), 비용이 빨리 지급되는 상태이기 때문', 'CFO 증가(+), 비용 지급을 뒤로 미룬 상태이기 때문', '영향 없음, 부채 항목이기 때문', 'CFO 감소(-), 구매 부담이 증가하기 때문', 2, '문서에서 매입채무 증가는 CFO 증가(+) 효과를 가져오며, 비용 지급을 뒤로 미룬 상태를 의미한다고 설명합니다.'),
(7, 10, '08', '현금흐름 주의', '문서에서 순이익 흑자, CFO 반복 적자 상황의 가능한 해석은?', '설비투자 부담이 크거나 성장 투자 단계', '유동성 압박 가능성', '매출채권·재고 증가, 이익의 질 저하', '성장 투자보다 자산 매각으로 현금 확보 가능성', 3, '문서 주의해야 할 현금흐름 표에서 순이익 흑자, CFO 반복 적자 상황은 매출채권·재고 증가, 이익의 질 저하로 해석할 수 있습니다.'),
(7, 11, '08', '현금흐름 주의', '문서에서 CFI 플러스가 반복될 때의 가능한 해석은?', '배당 지급이 늘어나는 신호', '본업 현금 부족을 차입·증자로 메우는 구조', '성장 투자보다 자산 매각으로 현금 확보 가능성', '설비투자 부담이 크거나 성장 투자 단계', 3, '문서 주의해야 할 현금흐름 표에서 CFI 플러스가 반복되면 성장 투자보다 자산 매각으로 현금을 확보하는 가능성을 의심해야 합니다.'),
(7, 12, '08', '현금흐름 명언', '문서에서 인용된 "이익은 의견이고, 현금은 사실이다"라는 표현이 강조하는 것은?', '영업이익이 손익계산서에서 가장 중요한 지표임', '손익보다 현금흐름이 더 중요한 경우가 있음', '매출액보다 순이익이 더 신뢰할 수 있음', '현금흐름표는 재무제표 중 가장 마지막에 보아야 함', 2, '문서에서 "이익은 의견이고, 현금은 사실이다(Earnings are an opinion; cash is a fact)"는 표현은 손익보다 현금이 더 중요한 경우가 있음을 강조합니다.'),
(7, 13, '08', '재무제표 3종 연결', '문서에서 재무제표 3종 연결 분석의 두 번째 순서에서 보는 표와 핵심 질문은?', '손익계산서 — 회사가 돈을 벌고 있는가?', '대차대조표/재무상태표 — 그 성장이 부채를 늘려 만든 것인가, 자본을 쌓아 만든 것인가?', '현금흐름표 — 회계상 이익이 실제 현금으로 들어오고 있는가?', '손익계산서 — 본업 이익률은 좋아지는가?', 2, '문서 재무제표 3종 연결 분석 표에서 두 번째 순서는 대차대조표/재무상태표이며, 핵심 질문은 그 성장이 부채를 늘려 만든 것인가, 자본을 쌓아 만든 것인가?입니다.'),
(7, 14, '08', '재무제표 3종 연결', '문서에서 순이익 증가 시 추가로 확인해야 할 표와 내용은?', '대차대조표의 매출채권·재고 — 현금 회수가 잘 되는 성장인지', '현금흐름표의 CFO — 이익이 실제 현금으로 바뀌는지', '대차대조표의 부채·자본 — 차입 성장인지 이익 누적 성장인지', '손익계산서의 향후 매출·이익 — 설비투자가 성과로 이어지는지', 2, '문서 연결해서 보는 대표 사례 표에서 순이익 증가 시 현금흐름표의 CFO를 보며 이익이 실제 현금으로 바뀌는지 확인해야 합니다.'),
(7, 15, '08', '기업가치 평가', '문서에서 기업가치(EV)와 주주가치(Equity Value)의 관계식으로 제시된 것은?', '기업가치(EV) = 주주가치 × 부채비율', '주주가치 = 기업가치(EV) + 순부채', '기업가치(EV) = 주주가치 + 순부채', '기업가치(EV) = 주주가치 - 자기자본', 3, '문서에서 기업가치(EV) = 주주가치 + 순부채, 주주가치 = 기업가치(EV) - 순부채로 정의됩니다.'),
(7, 16, '08', '기업가치 평가', '문서에서 기업가치(EV)가 중요한 이유는?', '실제 주가와 직접 연결되는 가치이기 때문', '부채 포함 기준이라 기업 자체 체력을 보기 좋기 때문', '자기자본만으로 기업 가치를 측정하기 때문', '배당 수익률과 직결되는 지표이기 때문', 2, '문서 기업가치(EV)와 주주가치(Equity Value) 구분 표에서 기업가치(EV)는 부채 포함 기준이라 기업 자체 체력을 보기 좋다고 설명됩니다.'),
(7, 17, '08', 'FCF 개념', '문서의 FCF 예시에서 CFO +200억, Capex -50억일 때 FCF는?', '+250억', '+150억', '+50억', '-50억', 2, '문서 FCF를 쉽게 이해하는 예시에서 FCF = CFO - Capex = 200억 - 50억 = +150억으로 계산됩니다.'),
(7, 18, '08', 'FCF 개념', '문서에서 FCF가 꾸준히 플러스인 기업의 특징으로 제시된 것은?', '이익 조작이 가능한 수준의 회계 능력', '외부 자금 없이 스스로 성장 가능', '부채비율이 낮아 재무 안전성 우수', '주가가 항상 내재가치보다 저평가', 2, '문서에서 FCF가 꾸준히 플러스인 기업은 외부 자금 없이 스스로 성장할 수 있다고 설명됩니다.'),
(7, 19, '08', 'DCF 개념', '문서에서 DCF 계산 flowchart의 Step 2로 제시된 것은?', 'FCF 예측 — 향후 5년간 연도별 FCF 추정', '현재가치 할인 — PV = FCFₙ ÷ (1+WACC)ⁿ', '영구가치 계산 — TV = FCF₅×(1+g) ÷ (WACC-g)', '주주가치 — Equity Value = EV - 순부채', 2, '문서 DCF 계산 flowchart에서 Step 2는 현재가치 할인으로, PV = FCFₙ ÷ (1+WACC)ⁿ 공식을 사용합니다.'),
(7, 20, '08', 'DCF 개념', '문서에서 WACC(할인율)를 쉽게 설명한 표현은?', '회사의 영업이익 대비 매출 비율', '이 회사의 돈 값(투자자 요구 수익률)', '부채 없이 사업을 운영하는 데 드는 비용', '시장 전체의 평균 수익률', 2, '문서에서 WACC를 쉽게 말해 "이 회사의 돈 값(투자자 요구 수익률)"이라고 설명합니다.'),
(7, 21, '08', 'DCF 개념', '문서에서 WACC 요소 중 자기자본비용의 일반적 범위로 제시된 것은?', '3~7%', '6~12%', '8~15%', '10~20%', 3, '문서 WACC 요소 표에서 자기자본비용(주주가 요구하는 수익률)의 일반적 범위는 8~15%로 제시됩니다.'),
(7, 22, '08', 'DCF 민감도', '문서에서 DCF 핵심 교훈으로 제시된 것은?', 'DCF는 정확한 답을 구하는 방법이다', 'WACC가 높을수록 기업가치가 높아진다', 'DCF는 가정을 바꿔가며 가치의 범위(보수~낙관)를 확인하는 도구이다', '영구성장률이 높을수록 기업가치가 낮아진다', 3, '문서에서 DCF의 핵심 교훈은 "정확한 답"을 구하는 게 아니라 가정을 바꿔가며 가치의 범위(보수~낙관)를 확인하는 도구라고 설명합니다.'),
(7, 23, '08', 'EVA 개념', '문서에서 EVA(경제적 부가가치)의 공식으로 제시된 것은?', 'EVA = 영업이익 - 이자비용', 'EVA = NOPAT - 투하자본 × WACC', 'EVA = 당기순이익 ÷ 자기자본 × 100', 'EVA = FCF - 자본비용', 2, '문서에서 EVA = NOPAT - 투하자본 × WACC로 정의되며, NOPAT은 세후 영업이익(금융손익 제외), 투하자본은 자기자본 + 이자부 부채입니다.'),
(7, 24, '08', 'EVA 개념', '문서에서 EVA < 0의 의미는?', '자본 비용을 내고도 남는 가치 창출', '딱 본전치기, 투자자 기대 충족 수준', '회계이익이 있어도 실질 가치 훼손', '영업이익이 없어 회사 운영이 불가능', 3, '문서 EVA 해석 방법 표에서 EVA < 0은 자본 비용도 못 벌어내는 구조로, 회계이익이 있어도 실질 가치 훼손을 의미합니다.'),
(7, 25, '08', 'EVA 개념', '문서의 A회사 EVA 예시에서 EVA 값은?', '+400억원', '-100억원', '+100억원', '+500억원', 3, '문서 EVA 예시에서 A회사의 EVA = NOPAT(500억) - 자본비용(4,000억 × 10% = 400억) = +100억원으로 가치 창출임을 보여줍니다.'),
(7, 26, '08', 'FCF·DCF·EVA 비교', '문서에서 EVA의 활용 시점으로 제시된 것은?', '현금 창출력 확인 시', '성장주 가치 평가 시', '자본 배분 효율성 점검 시', '내재가치 직접 추정 시', 3, '문서 세 가지 방법 비교 표에서 EVA의 활용 시점은 자본 배분 효율성 점검 시입니다.'),
(7, 27, '08', 'FCF·DCF·EVA 비교', '문서에서 DCF의 약점으로 제시된 것은?', '미래 성장성을 직접 반영 못함', '이익 조작이 어려운 현금 기반이라 조작이 쉬움', '가정에 매우 민감함', '자본 효율성을 평가하기 어려움', 3, '문서 FCF·DCF·EVA 세 가지 방법 비교 표에서 DCF의 약점은 가정에 매우 민감하다는 것입니다.'),
(7, 28, '08', 'DCF 실습', '문서의 Python DCF 코드에서 WACC가 영구성장률보다 작거나 같을 때 발생하는 처리는?', '경고 메시지 출력 후 계속 실행', 'ValueError("WACC는 영구성장률보다 커야 합니다.") 예외 발생', '0으로 처리해 결과 반환', 'None을 반환하고 종료', 2, '문서 DCF 계산 엔진 코드에서 wacc <= terminal_growth인 경우 ValueError("WACC는 영구성장률보다 커야 합니다.")를 발생시킵니다.'),
(7, 29, '08', 'DCF 실습 - 시나리오', '문서의 DCF 시나리오 분석에서 bear(보수) 시나리오의 WACC 값은?', '0.075 (7.5%)', '0.09 (9%)', '0.11 (11%)', '0.13 (13%)', 3, '문서 SCENARIOS 코드에서 bear(보수) 시나리오의 wacc는 0.11(11%)로, 가장 높은 할인율을 적용하는 보수적 가정입니다.'),
(7, 30, '08', 'DCF 실습 - 검증 규칙', '문서에서 Terminal Value 비중이 몇 % 이상이면 경고를 권장하는가?', '50% 이상', '60% 이상', '70% 이상', '80% 이상', 4, '문서 권장 검증 규칙 표에서 Terminal Value 비중이 80% 이상이면 경고를 권장하며, 이는 가치 대부분이 먼 미래 가정에 의존하기 때문입니다.');
